UPDATE /* @SQLID=SUB0204_01-04_1#Sql006 */ M_IPO_PO_BB_PERIOD
    SET
        ATTACHED_BRAND = #{req.brandCodeWith1}
        ,CIGARETTE_SHOW_FLAG = #{req.smokingCigarette}
        ,EDELIV_ONLY_FLAG = #{req.onlyElectronicDelivery}
        ,PAYMENT_DATE = #{req.depositScheduleDate}
        ,BB_PERIOD_FROM = #{req.bbPeriodFrom}
        ,BB_PERIOD_TO = #{req.bbPeriodTo}
        ,PRESENTATION_DATE = #{req.listedDate}


                ,PRICE = TO_NUMBER(#{req.issueBbPrice})


                ,PRICE = null


        ,UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
        ,UPDATE_USER = #{req.updateUser}
        ,SYS_ID = 'SUB0204_01-04_1'
        ,MAX_ALLOCATION = TO_NUMBER(#{req.maxAllocation})
        ,BB_PRESENTATION_FROM = TO_DATE(#{req.ifaBookBuildingPresentationFrom},'YYYY/MM/DD HH24:MI')
        ,BB_PRESENTATION_TO = TO_DATE(#{req.ifaBookBuildingPresentationTo},'YYYY/MM/DD HH24:MI')
        ,COM = TO_NUMBER(#{req.comm})
        ,CHANGE_PRICE_FLAG = #{req.changePriceFlag}
        ,CHANGE_PRICE_MSG = #{req.changePriceMsg}
        ,CHANGE_BB_PERIOD_FLAG = #{req.changeBbPeriodFlag}
        ,CHANGE_BB_PERIOD_MSG = #{req.changeBbPeriodMsg}
WHERE PRODUCT_CODE = #{req.brandCode}
AND PRESENTATION_FROM = TO_NUMBER(#{req.bookBuildingPresentationFrom})
AND TO_CHAR(UPDATE_TIME, 'yyyy/MM/dd hh24:mi:ss') = #{req.updateDate}
